import React, { useState, useEffect } from 'react';
import { getBooks, searchBooks, borrowBook, joinWaitingList } from '../api/api';

function BookList({ currentUserId, showToast }) {
  const [books, setBooks] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);

  const fetchBooks = async (query = '') => {
    setLoading(true);
    try {
      let response;
      if (query) {
        response = await searchBooks(query);
      } else {
        response = await getBooks();
      }
      setBooks(response.data);
    } catch (error) {
      console.error("Error fetching books:", error);
      showToast("Failed to load catalog. Is the server online?", "error");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBooks();
  }, []);

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    fetchBooks(searchQuery);
  };

  const handleBorrow = async (bookId, title) => {
    try {
      await borrowBook(currentUserId, bookId);
      showToast(`Successfully borrowed '${title}'!`, "success");
      fetchBooks(searchQuery);
    } catch (error) {
      const errMsg = error.response?.data?.error || `Failed to borrow book.`;
      showToast(errMsg, "error");
    }
  };

  const handleJoinWaitingList = async (bookId, title) => {
    try {
      const response = await joinWaitingList(currentUserId, bookId);
      const position = response.data.queuePosition;
      showToast(`Added to waiting list for '${title}'! Position: ${position}.`, "success");
      fetchBooks(searchQuery);
    } catch (error) {
      const errMsg = error.response?.data?.error || `Failed to join waiting list.`;
      showToast(errMsg, "error");
    }
  };

  return (
    <div className="catalog-container">
      <div className="page-title-bar">
        <h2>Book Catalog</h2>
        <p>Explore titles, checkout instantly, or reserve unavailable books.</p>
      </div>

      <div className="dashboard-card">
        <form onSubmit={handleSearchSubmit} className="search-bar">
          <input
            type="text"
            placeholder="Search books by title..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button type="submit" className="btn btn-primary">🔍 Search</button>
          {searchQuery && (
            <button
              type="button"
              className="btn btn-secondary"
              onClick={() => {
                setSearchQuery('');
                fetchBooks('');
              }}
            >
              Clear
            </button>
          )}
        </form>

        {loading ? (
          <div className="loading-state">Loading book library...</div>
        ) : books.length === 0 ? (
          <div className="empty-state">No books available in the catalog.</div>
        ) : (
          <div className="table-responsive">
            <table className="styled-table">
              <thead>
                <tr>
                  <th>Book Details</th>
                  <th>ISBN</th>
                  <th>Total Copies</th>
                  <th>Availability</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {books.map((book) => (
                  <tr key={book.id}>
                    <td>
                      <div className="book-title-cell">{book.title}</div>
                      <div className="book-author-cell">by {book.author}</div>
                    </td>
                    <td><code>{book.isbn}</code></td>
                    <td>{book.totalCopies}</td>
                    <td>
                      <span className={`badge ${book.availableCopies > 0 ? 'badge-success' : 'badge-danger'}`}>
                        {book.availableCopies} available
                      </span>
                    </td>
                    <td>
                      {book.availableCopies > 0 ? (
                        <button
                          className="btn btn-success btn-sm"
                          onClick={() => handleBorrow(book.id, book.title)}
                        >
                          📖 Borrow
                        </button>
                      ) : (
                        <button
                          className="btn btn-warning btn-sm"
                          onClick={() => handleJoinWaitingList(book.id, book.title)}
                        >
                          ⏳ Join Waiting List
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

export default BookList;
